// Get failures from Query Failed Loads
const failures = $('Query Failed Loads').all();

// Get retry counts
let retryCounts = [];
try {
  retryCounts = $('Get Retry Count').all();
} catch (error) {
  retryCounts = [];
}

// Create retry map - normalize to UPPERCASE for matching
const retryMap = {};
retryCounts.forEach(row => {
  if (row && row.json) {
    const pipeName = (row.json.PIPE_NAME || row.json.pipe_name || 'MANUAL_LOAD').toUpperCase();
    const fileName = (row.json.FILE_NAME || row.json.file_name || '').toUpperCase();
    const retryCount = row.json.RETRY_COUNT || row.json.retry_count || 0;

    if (fileName) {
      const key = `${pipeName}_${fileName}`;
      retryMap[key] = retryCount;
    }
  }
});

// Process each failure
const results = failures.map(failure => {
  const pipeName = (failure.json.PIPE_NAME || failure.json.pipe_name || 'MANUAL_LOAD').toUpperCase();
  const fileName = (failure.json.FILE_NAME || failure.json.file_name || '').toUpperCase();
  const errorMessage = failure.json.FIRST_ERROR_MESSAGE || failure.json.first_error_message || 'Unknown error';

  const key = `${pipeName}_${fileName}`;
  const retryCount = retryMap[key] || 0;

  return {
    json: {
      pipe_name: pipeName,
      file_name: fileName,
      error_message: errorMessage.substring(0, 200),
      retry_count: retryCount,
      should_retry: retryCount < 3,
      is_final_failure: retryCount >= 3
    }
  };
});

return results;

